+#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
+enum ScenarioCategory {
+    ReadSingle,
+    ReadAggregate,
+    WriteSingle,
+    WriteBulk,
+    ConcurrentWriters,
+    MixedOltp,
